import{_ as o,o as s,c as i,ai as l}from"./chunks/framework.CsYGeNYI.js";const b=JSON.parse('{"title":"出站会话镜像重构（Issue","description":"Track outbound session mirroring refactor notes, decisions, tests, and open items.","frontmatter":{"description":"Track outbound session mirroring refactor notes, decisions, tests, and open items.","title":"出站会话镜像重构（Issue","x-i18n":{"generated_at":"2026-02-03T07:53:51Z","model":"claude-opus-4-5","provider":"pi","source_hash":"b88a72f36f7b6d8a71fde9d014c0a87e9a8b8b0d449b67119cf3b6f414fa2b81","source_path":"refactor/outbound-session-mirroring.md","workflow":15}},"headers":[],"relativePath":"zh-CN/refactor/outbound-session-mirroring.md","filePath":"zh-CN/refactor/outbound-session-mirroring.md","lastUpdated":null}'),d={name:"zh-CN/refactor/outbound-session-mirroring.md"};function t(a,e,r,n,c,u){return s(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="出站会话镜像重构-issue-1520" tabindex="-1"><a class="header-anchor" href="#出站会话镜像重构-issue-1520">#</a> 出站会话镜像重构（Issue #1520）</h1><h2 id="状态" tabindex="-1"><a class="header-anchor" href="#状态">#</a> 状态</h2><ul><li>进行中。</li><li>核心 + 插件渠道路由已更新以支持出站镜像。</li><li>Gateway 网关发送现在在省略 sessionKey 时派生目标会话。</li></ul><h2 id="背景" tabindex="-1"><a class="header-anchor" href="#背景">#</a> 背景</h2><p>出站发送被镜像到<em>当前</em>智能体会话（工具会话键）而不是目标渠道会话。入站路由使用渠道/对等方会话键，因此出站响应落在错误的会话中，首次联系的目标通常缺少会话条目。</p><h2 id="目标" tabindex="-1"><a class="header-anchor" href="#目标">#</a> 目标</h2><ul><li>将出站消息镜像到目标渠道会话键。</li><li>在缺失时为出站创建会话条目。</li><li>保持线程/话题作用域与入站会话键对齐。</li><li>涵盖核心渠道加内置扩展。</li></ul><h2 id="实现摘要" tabindex="-1"><a class="header-anchor" href="#实现摘要">#</a> 实现摘要</h2><ul><li>新的出站会话路由辅助器： <ul><li><code>src/infra/outbound/outbound-session.ts</code></li><li><code>resolveOutboundSessionRoute</code> 使用 <code>buildAgentSessionKey</code>（dmScope + identityLinks）构建目标 sessionKey。</li><li><code>ensureOutboundSessionEntry</code> 通过 <code>recordSessionMetaFromInbound</code> 写入最小的 <code>MsgContext</code>。</li></ul></li><li><code>runMessageAction</code>（发送）派生目标 sessionKey 并将其传递给 <code>executeSendAction</code> 进行镜像。</li><li><code>message-tool</code> 不再直接镜像；它只从当前会话键解析 agentId。</li><li>插件发送路径使用派生的 sessionKey 通过 <code>appendAssistantMessageToSessionTranscript</code> 进行镜像。</li><li>Gateway 网关发送在未提供时派生目标会话键（默认智能体），并确保会话条目。</li></ul><h2 id="线程-话题处理" tabindex="-1"><a class="header-anchor" href="#线程-话题处理">#</a> 线程/话题处理</h2><ul><li>Slack：replyTo/threadId -&gt; <code>resolveThreadSessionKeys</code>（后缀）。</li><li>Discord：threadId/replyTo -&gt; <code>resolveThreadSessionKeys</code>，<code>useSuffix=false</code> 以匹配入站（线程频道 id 已经作用域会话）。</li><li>Telegram：话题 ID 通过 <code>buildTelegramGroupPeerId</code> 映射到 <code>chatId:topic:&lt;id&gt;</code>。</li></ul><h2 id="涵盖的扩展" tabindex="-1"><a class="header-anchor" href="#涵盖的扩展">#</a> 涵盖的扩展</h2><ul><li>Matrix、MS Teams、Mattermost、BlueBubbles、Nextcloud Talk、Zalo、Zalo Personal、Nostr、Tlon。</li><li>注意： <ul><li>Mattermost 目标现在为私信会话键路由去除 <code>@</code>。</li><li>Zalo Personal 对 1:1 目标使用私信对等方类型（仅当存在 <code>group:</code> 时才使用群组）。</li><li>BlueBubbles 群组目标去除 <code>chat_*</code> 前缀以匹配入站会话键。</li><li>Slack 自动线程镜像不区分大小写地匹配频道 id。</li><li>Gateway 网关发送在镜像前将提供的会话键转换为小写。</li></ul></li></ul><h2 id="决策" tabindex="-1"><a class="header-anchor" href="#决策">#</a> 决策</h2><ul><li><strong>Gateway 网关发送会话派生</strong>：如果提供了 <code>sessionKey</code>，则使用它。如果省略，从目标 + 默认智能体派生 sessionKey 并镜像到那里。</li><li><strong>会话条目创建</strong>：始终使用 <code>recordSessionMetaFromInbound</code>，<code>Provider/From/To/ChatType/AccountId/Originating*</code> 与入站格式对齐。</li><li><strong>目标规范化</strong>：出站路由在可用时使用解析后的目标（<code>resolveChannelTarget</code> 之后）。</li><li><strong>会话键大小写</strong>：在写入和迁移期间将会话键规范化为小写。</li></ul><h2 id="添加-更新的测试" tabindex="-1"><a class="header-anchor" href="#添加-更新的测试">#</a> 添加/更新的测试</h2><ul><li><code>src/infra/outbound/outbound-session.test.ts</code><ul><li>Slack 线程会话键。</li><li>Telegram 话题会话键。</li><li>dmScope identityLinks 与 Discord。</li></ul></li><li><code>src/agents/tools/message-tool.test.ts</code><ul><li>从会话键派生 agentId（不传递 sessionKey）。</li></ul></li><li><code>src/gateway/server-methods/send.test.ts</code><ul><li>在省略时派生会话键并创建会话条目。</li></ul></li></ul><h2 id="待处理项目-后续跟进" tabindex="-1"><a class="header-anchor" href="#待处理项目-后续跟进">#</a> 待处理项目 / 后续跟进</h2><ul><li>语音通话插件使用自定义的 <code>voice:&lt;phone&gt;</code> 会话键。出站映射在这里没有标准化；如果 message-tool 应该支持语音通话发送，请添加显式映射。</li><li>确认是否有任何外部插件使用内置集之外的非标准 <code>From/To</code> 格式。</li></ul><h2 id="涉及的文件" tabindex="-1"><a class="header-anchor" href="#涉及的文件">#</a> 涉及的文件</h2><ul><li><code>src/infra/outbound/outbound-session.ts</code></li><li><code>src/infra/outbound/outbound-send-service.ts</code></li><li><code>src/infra/outbound/message-action-runner.ts</code></li><li><code>src/agents/tools/message-tool.ts</code></li><li><code>src/gateway/server-methods/send.ts</code></li><li>测试： <ul><li><code>src/infra/outbound/outbound-session.test.ts</code></li><li><code>src/agents/tools/message-tool.test.ts</code></li><li><code>src/gateway/server-methods/send.test.ts</code></li></ul></li></ul>',21)])])}const g=o(d,[["render",t]]);export{b as __pageData,g as default};
